// รับ output จาก Form Trigger — รองรับทั้ง 2 ช่อง (Website URL / Facebook Page URL) กรอกอย่างน้อย 1 ช่อง
// normalize เป็น key คงที่ (website_url_direct, facebook_url) ให้ node ถัดไปอ้างอิงได้ชัวร์ไม่ว่า label จะเปลี่ยน
const raw = $input.first().json;
const facebookUrl = (raw['Facebook Page URL'] || raw.facebook_url || '').trim();
const websiteUrlDirect = (raw['Website URL'] || raw.website_url || '').trim();

if (!facebookUrl && !websiteUrlDirect) {
  throw new Error('ต้องกรอกอย่างน้อย 1 ช่อง: Website URL หรือ Facebook Page URL');
}

return [{ json: { facebook_url: facebookUrl, website_url_direct: websiteUrlDirect } }];

// ไม่มี Facebook Page URL — ข้ามการสแครป Facebook ทั้งหมด
// ส่ง shape เปล่า (เหมือน '3. Extract Website URL') ต่อให้ node merge ('3c. Resolve Brand Source')
// ไปประกอบกับ Website URL ตรงๆ (ถ้ามี) ต่อเอง
return [{
  json: {
    websiteUrl: null,
    fbSummary: '',
    pageName: '',
    followers: null,
    facebookUrl: ''
  }
}];

// รวมข้อมูลจาก 2 ทาง: Facebook page (pageName/fbSummary/followers) + Website URL ที่กรอกตรงๆ ใน form (ถ้ามี)
// Priority: Website URL ที่กรอกตรงๆ ชนะ website ที่ไปขุดเจอจาก Facebook about text (เชื่อถือได้กว่าเพราะ user ยืนยันมาเอง)
// แต่ pageName/fbSummary/followers จาก Facebook ยังใช้ต่อได้ตามปกติถ้ามี เพื่อให้ prompt ของ LLM ได้บริบทครบทั้ง 2 ทาง
const fbData = $input.first().json; // มาจาก '3. Extract Website URL' หรือ '3b. Skip Facebook (No FB Data)' — shape เดียวกัน
const directInput = $('1b. Normalize Input').first().json;

const websiteUrl = directInput.website_url_direct || fbData.websiteUrl || null;

let pageName = fbData.pageName || '';
if (!pageName && websiteUrl) {
  try {
    pageName = new URL(websiteUrl).hostname.replace(/^www\./, '');
  } catch (e) {
    pageName = websiteUrl;
  }
}

return [{
  json: {
    websiteUrl,
    fbSummary: fbData.fbSummary || '',
    pageName,
    followers: fbData.followers || null,
    facebookUrl: fbData.facebookUrl || directInput.facebook_url || ''
  }
}];

// ดึง website URL จาก Facebook page data (structured field ก่อน, fallback เป็น regex จาก about/intro text)
const items = $input.all();
const fbData = items[0].json[0] || items[0].json; // Apify sync-get-dataset-items คืนเป็น array

let websiteUrl = fbData.website || (fbData.intro && fbData.intro.website) || null;

if (!websiteUrl) {
  const aboutText = fbData.about || (fbData.intro ? JSON.stringify(fbData.intro) : '');
  const urlMatch = aboutText.match(/https?:\/\/[^\s"]+/);
  websiteUrl = urlMatch ? urlMatch[0] : null;
}

return [{
  json: {
    websiteUrl,
    fbSummary: fbData.about || '',
    pageName: fbData.pageName || fbData.title || '',
    followers: fbData.followers || fbData.likes || null,
    facebookUrl: fbData.pageUrl || fbData.url || ''
  }
}];

// รวม text จากหลายหน้าเว็บและตัดความยาว ป้องกัน token overflow
const items = $input.all();
let combined = '';

for (const item of items) {
  const data = item.json;
  if (Array.isArray(data)) {
    for (const page of data) {
      combined += (page.text || page.markdown || '') + '\n\n';
    }
  } else if (data.text || data.markdown) {
    combined += (data.text || data.markdown) + '\n\n';
  } else if (data.websiteContent) {
    combined += data.websiteContent;
  }
}

// จำกัดความยาว ~4000 words กันเกิน context/token limit
const words = combined.split(/\s+/);
const truncated = words.slice(0, 4000).join(' ');

return [{ json: { websiteContent: truncated } }];

// Parse ผลลัพธ์จาก Basic LLM Chain (chainLlm)

const input = $input.first().json;

let raw =
  input.text ||
  input.output ||
  input.response ||
  (input.candidates &&
    input.candidates[0] &&
    input.candidates[0].content.parts[0].text) ||
  '';

let profile;

try {
  profile = JSON.parse(raw);
} catch (e) {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  profile = JSON.parse(cleaned);
}

const extractNode = $('3c. Resolve Brand Source').first().json;

return [{
  json: {
    facebook_url: extractNode.facebookUrl,
    website_url: extractNode.websiteUrl,
    page_name: extractNode.pageName,

    industry: profile.industry || null,
    sub_niche: profile.sub_niche || null,
    brand_tone: profile.brand_tone || null,

    target_age_range: profile.target_audience?.age_range || null,
    target_gender_skew: profile.target_audience?.gender_skew || null,
    target_interests: profile.target_audience?.interests || [],

    price_positioning: profile.price_positioning || null,

    // ===== NEW FIELDS =====
    creator_search_keywords: profile.creator_search_keywords || [],
    hashtag_keywords: profile.hashtag_keywords || [],
    search_queries: profile.search_queries || [],
    creator_personas: profile.creator_personas || [],
    expertise_topics: profile.expertise_topics || [],

    // ===== EXISTING FIELDS =====
    product_keywords: profile.product_keywords || [],
    lifestyle_keywords: profile.lifestyle_keywords || [],
    content_style_fit: profile.content_style_fit || [],

    // Backward compatibility
    keywords: profile.keywords || [],

    raw_profile: profile
  }
}];

// สร้าง Search Terms สำหรับ TikTok Discovery
// รวม hashtag_keywords + creator_search_keywords
// ลบค่าซ้ำ และจำกัดจำนวนเพื่อประหยัด Apify Credit

const MAX_SEARCH_TERMS = 8;

const brand = $input.first().json;

// ลบ # ถ้ามี และจัดรูปแบบข้อความ
const normalize = (text) =>
  (text || "")
    .replace(/^#/, "")
    .replace(/[()]/g, "")
    .replace(/\s+/g, " ")
    .trim();

// รวม keyword จากหลายแหล่ง
const candidates = [
  ...(brand.hashtag_keywords || []),
  ...(brand.creator_search_keywords || [])
]
  .map(normalize)
  .filter(Boolean);

// ลบค่าซ้ำ
const uniqueTerms = [...new Set(candidates)].slice(0, MAX_SEARCH_TERMS);

if (uniqueTerms.length === 0) {
  throw new Error("ไม่พบ Search Keywords จาก Brand Profile");
}

// ส่งออกทีละคำ
return uniqueTerms.map(term => ({
  json: {
    search_term: term,
    brand_page_name: brand.page_name || "",
    source: (brand.hashtag_keywords || []).includes(term)
      ? "hashtag"
      : "creator_keyword"
  }
}));

// ดึง username ของเจ้าของวิดีโอจากผลลัพธ์ hashtag scraper แล้วเก็บสะสมแบบ dedupe ใน workflow static data
const items = $input.all();
let videos = [];

for (const item of items) {
  const data = item.json;
  if (Array.isArray(data)) {
    videos = videos.concat(data);
  } else if (data.items) {
    videos = videos.concat(data.items);
  } else {
    videos.push(data);
  }
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.usernames) staticData.usernames = [];

for (const v of videos) {
  const username = (v.authorMeta && v.authorMeta.name) || v.authorName || v.author || null;
  if (username && !staticData.usernames.includes(username)) {
    staticData.usernames.push(username);
  }
}

return [{ json: { hashtag: $('10. Loop Hashtags (1 at a time)').first().json.hashtag, accumulatedCount: staticData.usernames.length } }];

// อ่านรายชื่อ username ที่สะสมไว้ทั้งหมดจาก static data แล้วแปลงเป็น item แยกสำหรับ stage ถัดไป
// จำกัดจำนวนไว้ต่ำเพราะ credit Apify เหลือน้อย — node 14a (profile scraper) เป็นส่วนที่กิน
// compute unit เยอะสุดในทั้ง flow ยิ่งจำนวนคนเยอะยิ่งกินเครดิตเยอะตามสัดส่วน
// 10-15 คนก็เพียงพอสำหรับ prototype/demo แล้ว ไม่จำเป็นต้องมี KOL ครบทุกคนที่ discover เจอ
const TEST_LIMIT = 12; // <-- ปรับขึ้นได้ถ้าเช็ค Apify console แล้วเหลือ credit พอ

const staticData = $getWorkflowStaticData('global');
let usernames = staticData.usernames || [];

if (TEST_LIMIT) {
  usernames = usernames.slice(0, TEST_LIMIT);
}

return usernames.map(u => ({ json: { username: u } }));

// คำนวณ engagement rate เฉลี่ยจาก 10 วิดีโอล่าสุด แล้วเก็บ record ของ KOL คนนี้ลง static data
const items = $input.all();
let videos = [];
let profileMeta = null;

for (const item of items) {
  const data = item.json;
  if (Array.isArray(data)) {
    videos = videos.concat(data);
  } else {
    videos.push(data);
  }
}

if (videos.length > 0 && videos[0].authorMeta) {
  profileMeta = videos[0].authorMeta;
}

let totalViews = 0, totalLikes = 0, totalComments = 0, totalShares = 0;
const hashtagCount = {};

for (const v of videos) {
  totalViews += v.playCount || 0;
  totalLikes += v.diggCount || 0;
  totalComments += v.commentCount || 0;
  totalShares += v.shareCount || 0;
  const tags = v.hashtags || [];
  for (const h of tags) {
    const name = h.name || h;
    hashtagCount[name] = (hashtagCount[name] || 0) + 1;
  }
}

const videoCount = videos.length || 1;
const avgViews = totalViews / videoCount;
const avgLikes = totalLikes / videoCount;
const avgComments = totalComments / videoCount;
const engagementRate = avgViews > 0 ? (avgLikes + avgComments) / avgViews : null;

const topHashtags = Object.entries(hashtagCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 8)
  .map(([name]) => name);

const recentCaptions = videos.slice(0, 10).map(v => v.text || '').filter(Boolean);

const username = $('13. Loop Usernames (1 at a time)').first().json.username;

const record = {
  username,
  display_name: profileMeta ? profileMeta.nickName : null,
  bio: profileMeta ? profileMeta.signature : null,
  follower_count: profileMeta ? profileMeta.fans : null,
  following_count: profileMeta ? profileMeta.following : null,
  avg_views_last_10: Math.round(avgViews),
  avg_likes_last_10: Math.round(avgLikes),
  avg_comments_last_10: Math.round(avgComments),
  engagement_rate: engagementRate,
  top_hashtags_used: topHashtags,
  recent_video_captions: recentCaptions,
  profile_url: `https://www.tiktok.com/@${username}`,
  niche_tag: null
};

// ---------- ตรวจจับ owned-brand account (ตรรกะพอร์ตมาจาก matching_engine.py v4 is_likely_own_brand_account()) ----------
// สัญญาณหลัก: username ไปปรากฏซ้ำเป็นส่วนหนึ่งของ hashtag ที่ตัวเองใช้บ่อย (top_hashtags_used)
// ซึ่งเป็น pattern ทั่วไปของบัญชีแบรนด์ที่ใช้ branded-hashtag ของตัวเองซ้ำๆ ต่างจาก KOL อิสระที่รีวิวหลายแบรนด์สลับกันไป
// - ถ้ามีสัญญาณเสริมจาก bio ("บริษัท", "sales@") หรือ username ลงท้าย "official" ด้วย -> มั่นใจพอตัดออกอัตโนมัติ (_exclude_own_brand)
// - ถ้ามีแค่ username↔hashtag ตรงกันอย่างเดียว ไม่มั่นใจพอจะคัดออกเอง -> แค่ flag (possible_own_brand_account) ให้ตรวจสอบ ไม่ตัดออก
const OWN_BRAND_MIN_STEM_LENGTH = 4; // กันคำสั้นเกินไปที่จะ false positive ง่าย
const OWN_BRAND_BIO_SIGNALS = ['บริษัท', 'sales@'];

function extractUsernameStem(u) {
  if (!u) return '';
  const stem = u.split(/[.\d_]/)[0];
  return (stem || '').toLowerCase();
}

function isLikelyOwnBrandAccount(rec) {
  const stem = extractUsernameStem(rec.username);
  if (stem.length < OWN_BRAND_MIN_STEM_LENGTH) {
    return { shouldExclude: false, shouldFlag: false, matchedHashtag: '' };
  }
  const usernameLower = (rec.username || '').toLowerCase();
  const bioLower = (rec.bio || '').toLowerCase();
  const hashtags = rec.top_hashtags_used || [];

  let matchedHashtag = '';
  for (const tag of hashtags) {
    if ((tag || '').toLowerCase().includes(stem)) {
      matchedHashtag = tag;
      break;
    }
  }
  if (!matchedHashtag) {
    return { shouldExclude: false, shouldFlag: false, matchedHashtag: '' };
  }

  const hasBioSignal = usernameLower.includes('official') ||
    OWN_BRAND_BIO_SIGNALS.some(signal => bioLower.includes(signal));

  if (hasBioSignal) {
    return { shouldExclude: true, shouldFlag: false, matchedHashtag };
  }
  return { shouldExclude: false, shouldFlag: true, matchedHashtag };
}

const ownBrandCheck = isLikelyOwnBrandAccount(record);
record.possible_own_brand_account = ownBrandCheck.shouldFlag;
record._exclude_own_brand = ownBrandCheck.shouldExclude;
record._matched_own_brand_hashtag = ownBrandCheck.matchedHashtag;

const staticData = $getWorkflowStaticData('global');
if (!staticData.kolDataset) staticData.kolDataset = [];
staticData.kolDataset.push(record);

return [{ json: { username, accumulatedCount: staticData.kolDataset.length } }];

// รวบรวม KOL dataset ทั้งหมดที่สะสมไว้เป็น output สุดท้าย — schema นี้ตรงกับที่ matching_engine.py ใช้ตรงๆ
// niche_tag ยังเป็น null อยู่ — ถ้าต้องการ auto-classify ต่อ LLM node แยกได้ทีหลัง
const staticData = $getWorkflowStaticData('global');
const dataset = staticData.kolDataset || [];

return dataset.map(record => ({ json: record }));
